import {
  PUBLIC_API_BASE_URL,
  getSameHostApiBase,
  isPublicDomainHost
} from '@/config.js'

function getApiBase() {
  const envBase = typeof import.meta !== 'undefined' ? import.meta.env?.VITE_API_BASE_URL : ''
  if (typeof envBase === 'string' && envBase.trim()) return envBase.trim().replace(/\/+$/g, '')
  const host = typeof window === 'undefined' ? '' : window.location.hostname
  return isPublicDomainHost(host) ? PUBLIC_API_BASE_URL : getSameHostApiBase()
}

async function request(path, options = {}) {
  const res = await fetch(`${getApiBase()}${path}`, {
    headers: { 'Content-Type': 'application/json', ...(options.headers || {}) },
    ...options
  })
  if (!res.ok) {
    const message = await res.text()
    throw new Error(message || `HTTP_${res.status}`)
  }
  return res.json()
}

export function submitMatch(payload) {
  return request('/api/matches/finish', {
    method: 'POST',
    body: JSON.stringify(payload)
  })
}

export function fetchLeaderboard(type, limit = 50, playerId = '') {
  const mode = type === 'pve' ? 'pve' : 'pvp'
  const player = String(playerId || '').trim()
  const query = player
    ? `?limit=${encodeURIComponent(limit)}&playerId=${encodeURIComponent(player)}`
    : `?limit=${encodeURIComponent(limit)}`
  return request(`/api/leaderboard/${mode}${query}`)
}

