import { BLACK, WHITE } from '@/composables/gameConstants.js'

export const GAME_RECORD_VERSION = 1
export const GAME_RECORD_KIND = 'othello-reversi'
const RECORD_ID_MAX = 64

function formatFilenameTime(d = new Date()) {
  const pad = (n) => String(n).padStart(2, '0')
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}-${pad(d.getHours())}-${pad(d.getMinutes())}-${pad(d.getSeconds())}`
}

function sanitizeFilenamePart(s, fallback = 'player') {
  const v = String(s ?? '')
    .trim()
    .replace(/[<>:"/\\|?*\x00-\x1f]/g, '_')
    .replace(/\s+/g, '_')
    .slice(0, PLAYER_NAME_MAX)
  return v || fallback
}

/**
 * 默认下载文件名：本地时间 YYYY-MM-DD-HH-mm-ss.json
 */
export function defaultJsonFilename() {
  return `${formatFilenameTime()}.json`
}

export function buildGameRecordFilename(blackName, whiteName) {
  const b = sanitizeFilenamePart(blackName, 'black')
  const w = sanitizeFilenamePart(whiteName, 'white')
  return `${b}-vs-${w}-${formatFilenameTime()}.json`
}

const PLAYER_NAME_MAX = 24

function clipName(s) {
  return String(s ?? '')
    .trim()
    .slice(0, PLAYER_NAME_MAX)
}

function clipRecordId(v) {
  return String(v ?? '').trim().slice(0, RECORD_ID_MAX)
}

function formatMoveRows(rows) {
  const lines = ['[']
  for (let i = 0; i < rows.length; i += 5) {
    const chunk = rows.slice(i, i + 5)
    const rendered = chunk.map((row) => JSON.stringify(row)).join(', ')
    const suffix = i + 5 >= rows.length ? '' : ','
    lines.push(`    ${rendered}${suffix}`)
  }
  lines.push('  ]')
  return lines.join('\n')
}

/**
 * @param {{ gameOver: boolean, winner: string | null, moveLog: unknown[], playerNameBlack?: string, playerNameWhite?: string }} state
 */
export function serializeGameRecord(state) {
  const matchId = clipRecordId(state.matchId || state.recordId || state.gameId || '')
  const moveRows = Array.isArray(state.moveLog)
    ? state.moveLog.map((m) => [
      Number(m?.serial ?? 0),
      Number(m?.player ?? 0),
      Number(m?.index ?? -1),
      typeof m?.square === 'string' ? m.square : '',
      Number(m?.flipCount ?? 0)
    ])
    : []
  const payload = {
    version: GAME_RECORD_VERSION,
    game: GAME_RECORD_KIND,
    exportedAt: new Date().toISOString(),
    savedGameOver: state.gameOver ? 1 : 0,
    winner: state.winner || '',
    matchId,
    playerNames: {
      black: clipName(state.playerNameBlack),
      white: clipName(state.playerNameWhite)
    },
    matchMeta: {
      mode: String(state.mode || ''),
      recordId: matchId,
      startedAt: typeof state.startedAt === 'string' ? state.startedAt : '',
      finishedAt: typeof state.finishedAt === 'string' ? state.finishedAt : ''
    },
    players: {
      black: {
        id: String(state.players?.black?.id || ''),
        name: clipName(state.players?.black?.name || state.playerNameBlack),
        isAI: state.players?.black?.isAI ? 1 : 0
      },
      white: {
        id: String(state.players?.white?.id || ''),
        name: clipName(state.players?.white?.name || state.playerNameWhite),
        isAI: state.players?.white?.isAI ? 1 : 0
      }
    },
    moveHeader: ['serial', 'player', 'index', 'square', 'flipCount'],
    moveRows
  }
  const orderedKeys = [
    'version',
    'game',
    'exportedAt',
    'savedGameOver',
    'winner',
    'matchId',
    'playerNames',
    'matchMeta',
    'players',
    'moveHeader',
    'moveRows'
  ]
  const lines = orderedKeys.map((key) => {
    if (key !== 'moveRows') {
      return `  "${key}": ${JSON.stringify(payload[key])}`
    }
    return `  "moveRows": ${formatMoveRows(payload.moveRows)}`
  })
  return `{\n${lines.join(',\n')}\n}`
}

function isValidPlayer(p) {
  return p === BLACK || p === WHITE
}

/**
 * @param {string} text
 * @returns {{ savedGameOver: boolean, winner: string | null, moveLog: Array<{ serial: number, player: number, index: number, square: string, flipCount: number }>, playerNameBlack: string, playerNameWhite: string }}
 */
export function parseGameRecord(text) {
  let data
  try {
    data = JSON.parse(text)
  } catch {
    throw new Error('JSON')
  }
  if (!data || typeof data !== 'object') throw new Error('ROOT')
  const version = 'version' in data ? data.version : data.v
  const rows = 'moveRows' in data ? data.moveRows : data.r
  const winnerRaw = 'winner' in data ? data.winner : data.w
  const savedOverRaw = 'savedGameOver' in data ? data.savedGameOver : data.o
  const namesRaw = data.playerNames && typeof data.playerNames === 'object' ? data.playerNames : data.n
  const metaRaw = data.matchMeta && typeof data.matchMeta === 'object' ? data.matchMeta : data.m
  const playersRaw = data.players && typeof data.players === 'object' ? data.players : data.p

  if (!Array.isArray(rows) || (version == null)) throw new Error('FORMAT')
  if (version !== GAME_RECORD_VERSION) throw new Error('VERSION')
  if (!Array.isArray(rows)) throw new Error('MOVELOG')
  const log = []
  for (const m of rows) {
    if (!Array.isArray(m)) throw new Error('MOVE')
    const serial = Number(m[0])
    const player = Number(m[1])
    const index = Number(m[2])
    const square = typeof m[3] === 'string' ? m[3] : ''
    const flipCount = Number.isFinite(Number(m[4])) ? Number(m[4]) : 0
    if (!Number.isFinite(serial) || serial < 1) throw new Error('SERIAL')
    if (!isValidPlayer(player)) throw new Error('PLAYER')
    if (!Number.isFinite(index) || index < 0 || index > 63) throw new Error('INDEX')
    log.push({
      serial,
      player,
      index,
      square,
      flipCount
    })
  }

  const savedGameOver = Boolean(savedOverRaw)
  const winner =
    winnerRaw === 'black' || winnerRaw === 'white' || winnerRaw === 'draw'
      ? winnerRaw
      : savedGameOver
        ? null
        : null

  const playerNameBlack = clipName(
    namesRaw && typeof namesRaw === 'object'
      ? (namesRaw.black ?? (Array.isArray(namesRaw) ? namesRaw[0] : ''))
      : ''
  )
  const playerNameWhite = clipName(
    namesRaw && typeof namesRaw === 'object'
      ? (namesRaw.white ?? (Array.isArray(namesRaw) ? namesRaw[1] : ''))
      : ''
  )

  const compactMeta =
    metaRaw && typeof metaRaw === 'object' && !Array.isArray(metaRaw)
      ? metaRaw
      : {}
  const topMatchId = clipRecordId(
    'matchId' in data
      ? data.matchId
      : ('recordId' in data ? data.recordId : ('gameId' in data ? data.gameId : ''))
  )
  const metaMatchId = clipRecordId(compactMeta.recordId || compactMeta.matchId || compactMeta.gameId || '')
  const matchId = topMatchId || metaMatchId
  const compactPlayers =
    playersRaw && typeof playersRaw === 'object' && !Array.isArray(playersRaw)
      ? playersRaw
      : {}
  const compactBlack =
    compactPlayers.black && typeof compactPlayers.black === 'object'
      ? compactPlayers.black
      : {}
  const compactWhite =
    compactPlayers.white && typeof compactPlayers.white === 'object'
      ? compactPlayers.white
      : {}

  return {
    savedGameOver,
    winner,
    moveLog: log,
    playerNameBlack,
    playerNameWhite,
    mode: String(compactMeta.mode || ''),
    matchId,
    recordId: matchId,
    startedAt: String(compactMeta.startedAt || ''),
    finishedAt: String(compactMeta.finishedAt || ''),
    players: {
      black: {
        id: String(compactBlack.id || ''),
        name: clipName(compactBlack.name || playerNameBlack),
        isAI: Boolean(compactBlack.isAI)
      },
      white: {
        id: String(compactWhite.id || ''),
        name: clipName(compactWhite.name || playerNameWhite),
        isAI: Boolean(compactWhite.isAI)
      }
    }
  }
}

export function downloadTextFile(filename, text, mime = 'application/json;charset=utf-8') {
  const blob = new Blob([text], { type: mime })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = filename
  a.rel = 'noopener'
  document.body.appendChild(a)
  a.click()
  document.body.removeChild(a)
  URL.revokeObjectURL(url)
}
