const PLAYER_ID_KEY = 'othello-player-id'
const PLAYER_AVATAR_SEED_KEY = 'othello-player-avatar-seed'
const LOCAL_OPPONENT_ID_KEY = 'othello-local-opponent-id'
const LOCAL_OPPONENT_AVATAR_SEED_KEY = 'othello-local-opponent-avatar-seed'

function makeUuid() {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID()
  }
  const hex = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'
  return hex.replace(/[xy]/g, (c) => {
    const r = Math.random() * 16 | 0
    const v = c === 'x' ? r : (r & 0x3) | 0x8
    return v.toString(16)
  })
}

function readOrCreate(storageKey) {
  if (typeof localStorage === 'undefined') return makeUuid()
  try {
    const raw = String(localStorage.getItem(storageKey) || '').trim()
    if (raw) return raw
  } catch {
    // ignore
  }
  const value = makeUuid()
  try {
    localStorage.setItem(storageKey, value)
  } catch {
    // ignore
  }
  return value
}

export function getLocalIdentity() {
  const id = readOrCreate(PLAYER_ID_KEY)
  const avatarSeed = readOrCreate(PLAYER_AVATAR_SEED_KEY)
  return {
    id,
    avatarSeed,
    avatarUrl: `https://api.dicebear.com/7.x/bottts-neutral/svg?seed=${encodeURIComponent(avatarSeed)}`
  }
}

export function getLocalOpponentIdentity() {
  const id = readOrCreate(LOCAL_OPPONENT_ID_KEY)
  const avatarSeed = readOrCreate(LOCAL_OPPONENT_AVATAR_SEED_KEY)
  return {
    id,
    avatarSeed,
    avatarUrl: `https://api.dicebear.com/7.x/bottts-neutral/svg?seed=${encodeURIComponent(avatarSeed)}`
  }
}
