<template>
  <div
    class="cell"
    :class="{
      'clickable': isClickable && isHoverable,
      'black': cellValue === BLACK,
      'white': cellValue === WHITE
    }"
    @click="handleClick"
  >
    <!-- 黑棋 -->
    <div
      v-if="cellValue === BLACK"
      class="piece black"
      :class="{ 'new': isNewMove }"
    >
      <span
        v-if="pieceMeta"
        class="piece-serial"
        :class="{ 'piece-serial--won': pieceMeta.flipped, 'piece-serial--last': isNewMove }"
      >{{ pieceMeta.serial }}</span>
    </div>

    <!-- 白棋 -->
    <div
      v-else-if="cellValue === WHITE"
      class="piece white"
      :class="{ 'new': isNewMove }"
    >
      <span
        v-if="pieceMeta"
        class="piece-serial"
        :class="{ 'piece-serial--won': pieceMeta.flipped, 'piece-serial--last': isNewMove }"
      >{{ pieceMeta.serial }}</span>
    </div>

    <!-- 可落子提示 -->
    <div
      v-else-if="isValidMove && showMoveGain"
      class="gain-hint"
      :class="{ 'gain-hint--max': isMaxMoveGain }"
    >
      {{ moveGain }}
    </div>
    <div
      v-else-if="isValidMove && showHint"
      class="hint"
    />
  </div>
</template>

<script setup>
import { computed } from 'vue'
import { EMPTY, BLACK, WHITE } from '@/composables'

const props = defineProps({
  cellValue: {
    type: Number,
    default: EMPTY
  },
  index: {
    type: Number,
    required: true
  },
  isValidMove: {
    type: Boolean,
    default: false
  },
  lastMoveIndex: {
    type: Number,
    default: -1
  },
  isClickable: {
    type: Boolean,
    default: true
  },
  showHint: {
    type: Boolean,
    default: true
  },
  pieceMeta: {
    type: Object,
    default: null
  },
  moveGain: {
    type: Number,
    default: 0
  },
  showMoveGain: {
    type: Boolean,
    default: false
  },
  isMaxMoveGain: {
    type: Boolean,
    default: false
  }
})

const emit = defineEmits(['click'])

const isNewMove = computed(() => props.index === props.lastMoveIndex)

const isHoverable = computed(() => props.isValidMove && props.cellValue === EMPTY)

function handleClick() {
  if (props.isClickable && props.isValidMove) {
    emit('click', props.index)
  }
}
</script>

