    rgba(220, 38, 38, 0.22) 100%
  );
  box-shadow:
    0 0 0 1px rgba(248, 113, 113, 0.45),
    0 0 12px rgba(220, 38, 38, 0.75);
}

.piece.black {
  background: radial-gradient(circle at 35% 35%, #334155, #0f172a);
  box-shadow: 2px 2px 6px rgba(0, 0, 0, 0.6);
}

.piece.white {
  background: radial-gradient(circle at 35% 35%, #fff, #e2e8f0);
