export const PUBLIC_SITE_DOMAIN = 'kyletang.work'
export const PUBLIC_API_BASE_URL = 'https://nas.1yu.cn:12346'
export const PUBLIC_WS_URL = 'wss://nas.1yu.cn:12345'
export const LOCAL_API_BASE_URL = 'http://localhost:18080'
export const LOCAL_WS_URL = 'ws://localhost:18080'
export const SAME_HOST_SERVER_PORT = 18080

export function isPublicDomainHost(hostname) {
  return String(hostname || '').trim() === PUBLIC_SITE_DOMAIN
}

export function getSameHostApiBase() {
  if (typeof window === 'undefined') return LOCAL_API_BASE_URL
  return `${window.location.protocol}//${window.location.hostname}:${SAME_HOST_SERVER_PORT}`
}

export function getSameHostWsUrl() {
  if (typeof window === 'undefined') return LOCAL_WS_URL
  const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:'
  return `${protocol}//${window.location.hostname}:${SAME_HOST_SERVER_PORT}`
}
