function fillMissingKeys(target, fallback) {
  if (!target || typeof target !== 'object' || !fallback || typeof fallback !== 'object') return
  for (const [key, value] of Object.entries(fallback)) {
    if (!(key in target)) {
      target[key] = value
      continue
    }
    if (
      value &&
      typeof value === 'object' &&
      !Array.isArray(value) &&
      target[key] &&
      typeof target[key] === 'object' &&
      !Array.isArray(target[key])
    ) {
      fillMissingKeys(target[key], value)
    }
  }
}

for (const code of Object.keys(messages)) {
  fillMissingKeys(messages[code], COMMON_I18N_FALLBACK)
}
