function parseAuthProfile(raw) {
  if (!raw || typeof raw !== 'object') return null
  const playerId = String(raw.playerId || '').trim()
  const avatarSeed = String(raw.avatarSeed || '').trim()
  const loginName = String(raw.loginName || '').trim()
  const nickname = String(raw.nickname || '').trim()
  if (!playerId || !avatarSeed || !loginName || !nickname) return null
  return {
    playerId,
    avatarSeed,
    loginName,
    nickname,
    password: String(raw.password || ''),
    isGuest: Boolean(raw.isGuest),
    hasPassword: Boolean(raw.hasPassword)
  }
}

function readCachedAuthProfile() {
  if (typeof localStorage === 'undefined') return null
  try {
    const raw = JSON.parse(localStorage.getItem(AUTH_PROFILE_STORAGE_KEY) || 'null')
    return parseAuthProfile(raw)
  } catch {
    return null
  }
}

function readLastLoginName() {
  if (typeof localStorage === 'undefined') return ''
  try {
    return String(localStorage.getItem(LAST_LOGIN_NAME_STORAGE_KEY) || '').trim()
  } catch {
    return ''
  }
}

function readLoggedOutFlag() {
  if (typeof localStorage === 'undefined') return false
  try {
    return String(localStorage.getItem(AUTH_LOGGED_OUT_KEY) || '') === '1'
  } catch {
    return false
  }
}

function persistIdentityFromProfile(profile) {
  if (typeof localStorage === 'undefined' || !profile) return
  try {
    localStorage.setItem(PLAYER_ID_KEY, profile.playerId)
    localStorage.setItem(PLAYER_AVATAR_SEED_KEY, profile.avatarSeed)
    localStorage.setItem(NETWORK_NAME_STORAGE_KEY, profile.nickname)
  } catch {
    // ignore
  }
}

