    ? t('network.connectedTo', { server: connectedServerLabel.value })
    : ''
  if (partnerAwayMsg.value) {
    return `${connectedPrefix}${partnerAwayMsg.value}`
  }
  if (netState.value === 'connecting') return t('network.connecting')
  if (netState.value === 'joined') return `${connectedPrefix}${t('network.ready')}`
  if (netState.value === 'matched') {
    return `${connectedPrefix}${t('network.matchedCountdown', { sec: countdownSec.value })}`
  }
  if (netState.value === 'playing') return `${connectedPrefix}${t('network.playing')}`
  if (netState.value === 'waiting-rematch') return `${connectedPrefix}${t('network.waitingRematch')}`
  if (netState.value === 'closed') return t('network.closed')
