const SAFE_CODE_CHARS = '23456789ABCDEFGHJKLMNPQRSTUVWXYZ'

function makeSafeCode(len = 4) {
  let out = ''
  for (let i = 0; i < len; i += 1) {
    out += SAFE_CODE_CHARS[Math.floor(Math.random() * SAFE_CODE_CHARS.length)]
  }
  return out
}

function persistAuthProfile(profile) {
  if (typeof localStorage === 'undefined') return
  const normalized = parseAuthProfile(profile)
  if (!normalized) return
  try {
    localStorage.setItem(AUTH_PROFILE_STORAGE_KEY, JSON.stringify(normalized))
    localStorage.setItem(LAST_LOGIN_NAME_STORAGE_KEY, normalized.loginName)
    localStorage.removeItem(AUTH_LOGGED_OUT_KEY)
  } catch {
    // ignore
  }
  persistIdentityFromProfile(normalized)
}

function clearAuthCache() {
  if (typeof localStorage === 'undefined') return
  try {
    localStorage.removeItem(AUTH_PROFILE_STORAGE_KEY)
  } catch {
    // ignore
  }
}

async function onSubmitAuth() {
  authError.value = ''
  const loginName = String(authForm.value.loginName || '').trim()
  const password = String(authForm.value.password || '')
  let nickname = String(authForm.value.nickname || '').trim()
  if (!loginName) {
    authError.value = t('errors.auth.loginNameRequired')
    return
  }
  if (authMode.value === 'register' && !password) {
    authError.value = t('errors.auth.passwordRequiredForRegister')
    return
  }
  if (authMode.value === 'register' && !nickname) {
    nickname = `${t('player.default1')}${makeSafeCode(4)}`
  }
  authSubmitting.value = true
  try {
    const res = authMode.value === 'register'
      ? await authRegister({ loginName, password, nickname })
      : await authLogin({ loginName, password })
    const profile = parseAuthProfile({
      ...(res?.profile || {}),
      password: res?.profile?.hasPassword ? password : ''
    })
    if (!profile) throw new Error('INVALID_PROFILE')
    authProfile.value = profile
    profileDraft.value = { loginName: profile.loginName, nickname: profile.nickname }
    persistAuthProfile(profile)
    window.location.reload()
  } catch (err) {
    authError.value = t('errors.auth.actionFailed', { message: err?.message || err })
  } finally {
    authSubmitting.value = false
  }
}

async function onGuestAuth() {
  authError.value = ''
  authSubmitting.value = true
  try {
    const res = await authGuest()
    const profile = parseAuthProfile({ ...(res?.profile || {}), password: '' })
    if (!profile) throw new Error('INVALID_PROFILE')
    authProfile.value = profile
    profileDraft.value = { loginName: profile.loginName, nickname: profile.nickname }
    persistAuthProfile(profile)
    window.location.reload()
  } catch (err) {
    authError.value = t('errors.auth.guestLoginFailed', { message: err?.message || err })
  } finally {
    authSubmitting.value = false
  }
}

function getApiErrorCode(err) {
  const raw = String(err?.message || '').trim()
  if (!raw) return ''
  if (!raw.startsWith('{')) return raw
  try {
    const parsed = JSON.parse(raw)
    return String(parsed?.error || '').trim()
  } catch {
    return raw
  }
}

async function onSaveProfile(field = 'all') {
  profileError.value = ''
  const playerId = String(authProfile.value.playerId || '').trim()
  const loginName = String(profileDraft.value.loginName || '').trim()
  const nickname = String(profileDraft.value.nickname || '').trim()
  if (!playerId) {
    profileError.value = t('errors.auth.notLoggedIn')
    return
  }
  if (field === 'loginName' && !loginName) {
    profileError.value = t('errors.auth.loginNameEmpty')
    return
  }
  if (field === 'nickname' && !nickname) {
    profileError.value = t('errors.auth.nicknameEmpty')
    return
  }
  if (!loginName || !nickname) {
    profileError.value = t('errors.auth.loginAndNicknameRequired')
    return
  }
  try {
    const res = await authUpdateProfile({ playerId, loginName, nickname })
    const next = parseAuthProfile({
      ...(res?.profile || {}),
      password: authProfile.value.password
    })
    if (!next) throw new Error('INVALID_PROFILE')
    authProfile.value = next
    profileDraft.value = { loginName: next.loginName, nickname: next.nickname }
    persistAuthProfile(next)
    networkPlayerName.value = next.nickname
    playerNameBlack.value = next.nickname
    await showAlert(t('messages.profileUpdated'))
    accountDialogOpen.value = false
    refreshLeaderboards()
  } catch (err) {
    const code = getApiErrorCode(err)
    if (code === 'LOGIN_NAME_TAKEN') {
      profileError.value = t('errors.auth.loginNameTaken')
      return
    }
    if (code === 'NICKNAME_TAKEN') {
      profileError.value = t('errors.auth.nicknameTaken')
      return
    }
    profileError.value = t('errors.common.saveFailed', { message: err?.message || err })
  }
}

async function onSavePassword() {
  passwordError.value = ''
  const playerId = String(authProfile.value.playerId || '').trim()
  const oldPassword = String(passwordDraft.value.oldPassword || '')
  const newPassword = String(passwordDraft.value.newPassword || '')
  const confirmPassword = String(passwordDraft.value.confirmPassword || '')
  if (!playerId) {
    passwordError.value = t('errors.auth.notLoggedIn')
    return
  }
  if (newPassword.length < 4) {
    passwordError.value = t('errors.auth.newPasswordTooShort')
    return
  }
  if (newPassword !== confirmPassword) {
    passwordError.value = t('errors.auth.passwordMismatch')
    return
  }
  if (authProfile.value.hasPassword && !oldPassword) {
    passwordError.value = t('errors.auth.oldPasswordRequired')
    return
  }
  try {
    const res = await authUpdatePassword({ playerId, oldPassword, newPassword })
    const next = parseAuthProfile({
      ...(res?.profile || {}),
      password: newPassword
    })
    if (!next) throw new Error('INVALID_PROFILE')
    authProfile.value = next
    persistAuthProfile(next)
    passwordDraft.value = { oldPassword: '', newPassword: '', confirmPassword: '' }
    await showAlert(t('messages.passwordUpdated'))
    passwordDialogOpen.value = false
  } catch (err) {
    passwordError.value = t('errors.auth.passwordUpdateFailed', { message: err?.message || err })
  }
}

