async function onClearAuthCache() {
  if (!(await showConfirm(t('messages.confirmClearCache')))) return
  if (typeof localStorage !== 'undefined') {
    const keepKeys = new Set([
      AUTH_PROFILE_STORAGE_KEY,
      LAST_LOGIN_NAME_STORAGE_KEY,
      AUTH_LOGGED_OUT_KEY,
      PLAYER_ID_KEY,
      PLAYER_AVATAR_SEED_KEY,
      NETWORK_NAME_STORAGE_KEY
    ])
    try {
      const keys = []
      for (let i = 0; i < localStorage.length; i += 1) {
        const k = localStorage.key(i)
        if (k) keys.push(k)
      }
      for (const key of keys) {
        if (!String(key).startsWith('othello-')) continue
        if (keepKeys.has(key)) continue
        localStorage.removeItem(key)
      }
    } catch {
      // ignore
    }
  }
  await showAlert(t('messages.cacheCleared'))
}

