async function reportMatchResult() {
  if (!gameOver.value) return
  if (gameMode.value === 'pvn' && localColor.value !== 'black') return
  const players = getPlayersForCurrentMatch()
  const finalJson = buildExportJson({ players })
  const signature = `${gameMode.value}:${winner.value}:${moveLog.value.length}:${players.black.id}:${players.white.id}`
  if (lastSubmittedSignature === signature) return
  try {
    const res = await submitMatch({
      mode: gameMode.value === 'pvn' ? 'pvp' : gameMode.value,
      winner: winner.value,
      blackScore: Number(scores.value?.black || 0),
      whiteScore: Number(scores.value?.white || 0),
      moveCount: moveLog.value.length,
      finalJson,
      players,
      reporterId: myIdentity.id
    })
    if (res?.myStats) myStats.value = res.myStats
    if (typeof res?.excitementScore === 'number') {
      currentMatchExcitementScore.value = res.excitementScore
    }
    lastSubmittedSignature = signature
    await refreshLeaderboards()
  } catch (err) {
    console.error('Failed to submit match:', err)
  }
}

async function refreshLeaderboards() {
  try {
    const [pvp, pve, featured, experts, recent, saves] = await Promise.all([
      fetchLeaderboard('pvp', 20, myIdentity.id),
      fetchLeaderboard('pve', 20, myIdentity.id),
      fetchFeaturedGames(20),
      fetchFeaturedExperts(20),
      fetchMyRecentMatches(myIdentity.id, 20),
      fetchSavedRecords(myIdentity.id, 40)
    ])
    pvpBoard.value = Array.isArray(pvp?.items) ? pvp.items : []
    pveBoard.value = Array.isArray(pve?.items) ? pve.items : []
    featuredGames.value = Array.isArray(featured?.items) ? featured.items : []
    featuredExpertsBoard.value = Array.isArray(experts?.items) ? experts.items : []
    myRecentMatches.value = Array.isArray(recent?.items) ? recent.items : []
    serverSaves.value = Array.isArray(saves?.items) ? saves.items : []
    if (pvp?.myStats || pve?.myStats) {
      myStats.value = {
        pvp: pvp?.myStats || myStats.value.pvp,
        pve: pve?.myStats || myStats.value.pve
      }
    }
  } catch (err) {
    console.error('Failed to fetch boards:', err)
  }
}

function formatMatchTime(value) {
