  return `${datePart}\n${timePart}`
}

function getOpponentName(item) {
  const myId = String(myIdentity.id || '')
  const blackId = String(item?.blackPlayerId || item?.blackId || '')
  const whiteId = String(item?.whitePlayerId || item?.whiteId || '')
  const blackName = String(item?.blackName || '')
  const whiteName = String(item?.whiteName || '')
  if (blackId && myId && blackId === myId) return whiteName || '-'
  if (whiteId && myId && whiteId === myId) return blackName || '-'
  const selfName = String(playerDisplayName.value || '').trim()
  if (selfName && blackName === selfName) return whiteName || '-'
  if (selfName && whiteName === selfName) return blackName || '-'
  return whiteName || blackName || '-'
}

function formatOpponentDisplay(name) {
  const s = String(name || '')
  if (s.length <= 6) return s
  return `${s.slice(0, 6)}..`
}

function formatRankPlayerDisplay(name) {
  const s = String(name || '')
  if (s.length <= 6) return s
  return `${s.slice(0, 6)}..`
}

function formatSavedPlayersInline(s) {
  const payload = s?.payload || {}
  const names = payload.playerNames || payload.n || {}
  const black = String(names.black || names[0] || '').trim() || t('player.default1')
  const white = String(names.white || names[1] || '').trim() || t('player.default2')
  const winner = String(payload.winner || payload.w || '')
  const blackText = winner === 'black' ? `${black} 👑` : black
  const whiteText = winner === 'white' ? `${white} 👑` : white
  return `${blackText} ${t('scoreboard.vs')} ${whiteText}`
}

function formatSavedMetaInline(s) {
  const payload = s?.payload || {}
  const rm = payload.resultMeta && typeof payload.resultMeta === 'object'
    ? payload.resultMeta
    : {}
  const black = Number.isFinite(Number(rm.blackScore)) ? Number(rm.blackScore) : '-'
  const white = Number.isFinite(Number(rm.whiteScore)) ? Number(rm.whiteScore) : '-'
  const ex = Number.isFinite(Number(rm.excitementScore)) ? Number(rm.excitementScore) : '-'
  const mc = Number.isFinite(Number(s?.moveCount)) ? Number(s.moveCount) : '-'
  let timeText = '-'
  const savedAt = String(s?.savedAt || '')
  if (savedAt) {
    const d = new Date(savedAt)
    if (!Number.isNaN(d.getTime())) {
      const pad = (n) => String(n).padStart(2, '0')
      timeText = `${d.getFullYear()}/${pad(d.getMonth() + 1)}/${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`
    }
  }
  return t('mine.savedMetaLine', { black, white, excitement: ex, moves: mc, time: timeText })
}

function getMyMatchResult(item) {
  const winner = String(item?.winner || '')
  if (winner === 'draw') return { label: t('mine.resultDrawShort'), type: 'draw' }
  const myId = String(myIdentity.id || '')
  const blackId = String(item?.blackPlayerId || item?.blackId || '')
  const whiteId = String(item?.whitePlayerId || item?.whiteId || '')
  let myColor = ''
  if (myId && blackId === myId) myColor = 'black'
  else if (myId && whiteId === myId) myColor = 'white'
  else {
    const selfName = String(playerDisplayName.value || '').trim()
    if (selfName && String(item?.blackName || '') === selfName) myColor = 'black'
    else if (selfName && String(item?.whiteName || '') === selfName) myColor = 'white'
  }
  if (!myColor || !winner) return { label: '-', type: 'draw' }
  return winner === myColor
    ? { label: t('mine.resultWinShort'), type: 'win' }
    : { label: t('mine.resultLoseShort'), type: 'lose' }
}

function escapeRegex(value) {
  return String(value || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
}

function matchesPlayerFilter(name, keyword) {
  const n = String(name || '').trim()
  if (!n) return false
  if (!keyword.includes('*')) {
    return n === keyword
  }
  const pattern = `^${escapeRegex(keyword).replace(/\\\*/g, '.*')}$`
  return new RegExp(pattern, 'i').test(n)
}

