async function handleRealtimeMessage(data) {
  if (!data || typeof data !== 'object') return
  if (data.type === 'joined') {
    localColor.value = data.color || ''
    applyMatchedPlayers(data.players)
    netState.value = 'joined'
    networkErrorMsg.value = ''
    partnerAwayMsg.value = ''
    return
  }
  if (data.type === 'partner-away') {
    partnerAwayMsg.value =
      data.reason === 'leave'
        ? t('network.partnerLeft')
        : t('network.partnerDisconnected')
    return
  }
  if (data.type === 'room-update') {
    networkErrorMsg.value = ''
    applyMatchedPlayers(data.players)
    if (data.matched) {
      partnerAwayMsg.value = ''
      startMatchCountdown(3)
    } else {
      netState.value = 'joined'
    }
    return
  }
  if (data.type === 'move') {
    handlePlayerMove(Number(data.index))
    return
  }
  if (data.type === 'rematch-waiting') {
    rematchWaiting.value = true
    netState.value = 'waiting-rematch'
    return
  }
  if (data.type === 'rematch-invite') {
    const ok = await showConfirm(t('network.rematchInviteConfirm'))
    realtimeClient?.send({ type: 'rematch-response', accept: Boolean(ok) })
    if (!ok) {
      onLeaveRoom()
    }
    return
  }
  if (data.type === 'rematch-start') {
    rematchWaiting.value = false
    initGame()
    netState.value = 'playing'
    return
  }
  if (data.type === 'error') {
    if (data.code === 'ROOM_FULL') {
      await showAlert(t('network.roomFull'))
      onLeaveRoom()
      return
    }
    if (data.code === 'NAME_TAKEN') {
      await showAlert(t('network.nameTaken'))
      onLeaveRoom()
      return
    }
    networkErrorMsg.value = data.message || 'unknown error'
  }
}

function disconnectNetwork() {
  connectSequenceId += 1
  resetCountdownTimer()
  rematchWaiting.value = false
  if (realtimeClient) {
    manualDisconnecting.value = true
    realtimeClient.send({ type: 'leave' })
    realtimeClient.close()
    realtimeClient = null
  }
  localColor.value = ''
  matchedPlayers.value = { blackName: '', whiteName: '' }
  matchedPlayerIds.value = { blackId: '', whiteId: '' }
  connectedServerLabel.value = ''
  netState.value = 'idle'
  networkErrorMsg.value = ''
  partnerAwayMsg.value = ''
}

function onLeaveRoom() {
  disconnectNetwork()
}

async function onJoinRoom() {
  const roomCode = normalizeRoomCode(roomCodeInput.value)
  roomCodeInput.value = roomCode
  if (!/^\d{6}$/.test(roomCode)) {
    await showAlert(t('network.invalidRoomCode'))
    return
  }
  const myName = String(networkPlayerName.value || '').trim().slice(0, 24) || t('player.default1')
  networkPlayerName.value = myName
  playerNameBlack.value = myName
  disconnectNetwork()
  netState.value = 'connecting'
  const host = typeof window === 'undefined' ? '' : window.location.hostname
  const attempts = isPublicDomainHost(host)
    ? [{ url: PUBLIC_WS_URL, label: t('network.publicServer') }]
    : [{ url: getSameHostWsUrl(), label: t('network.sameHostServer') }]

  const seqId = ++connectSequenceId
  const connectAt = (idx) => {
    if (seqId !== connectSequenceId) return
    const attempt = attempts[idx]
    realtimeClient = createRealtimeClient({
      serverUrl: attempt.url,
      roomCode,
      playerName: myName,
      playerId: myIdentity.id,
      avatarSeed: myIdentity.avatarSeed,
      onOpen: () => {
        if (seqId !== connectSequenceId) return
        networkErrorMsg.value = ''
        partnerAwayMsg.value = ''
      },
      onClose: () => {
        if (seqId !== connectSequenceId) return
        const manual = manualDisconnecting.value
        manualDisconnecting.value = false
        if (manual) {
          if (gameMode.value === 'pvn') netState.value = 'idle'
          return
        }
        if (gameMode.value === 'pvn') {
          netState.value = 'closed'
        }
      },
      onError: (err) => {
        if (seqId !== connectSequenceId) return
        networkErrorMsg.value = err?.message || String(err)
      },
      onMessage: (data) => {
        if (seqId !== connectSequenceId) return
        if (data?.type === 'joined') {
          connectedServerLabel.value = attempt.label
        }
        handleRealtimeMessage(data)
      }
    })
  }
  connectAt(0)
}

