async function onSaveLocal() {
  try {
    const players = getPlayersForCurrentMatch()
    const payload = buildExportJson({ players })
    let payloadObj = null
    try {
      payloadObj = JSON.parse(payload)
    } catch {
      payloadObj = null
    }
    if (payloadObj && typeof payloadObj === 'object') {
      payloadObj.resultMeta = {
        blackScore: Number(scores.value?.black || 0),
        whiteScore: Number(scores.value?.white || 0),
        excitementScore: currentMatchExcitementScore.value == null
          ? null
          : Number(currentMatchExcitementScore.value)
      }
    }
    const payloadForSave = payloadObj ? JSON.stringify(payloadObj) : payload
    await saveGameRecordToServer({
      playerId: myIdentity.id,
      label: defaultJsonFilename().replace(/\.json$/i, ''),
      moveCount: moveLog.value.length,
      recordId: String(payloadObj?.matchId || payloadObj?.matchMeta?.recordId || '').trim(),
      recordJson: payloadForSave
    })
    await refreshLeaderboards()
    await showAlert(t('side.saveOk'))
  } catch (err) {
    if (err?.message === 'DUPLICATE_RECORD') {
      await showAlert(t('messages.recordAlreadySaved'))
      return
    }
    await showAlert(
      err?.message === 'QUOTA' ? t('side.saveQuota') : err?.message || String(err)
    )
  }
}

async function onLoadLocalSave(id) {
  try {
    const detail = await fetchSavedRecordById(id, myIdentity.id)
    const payload = detail?.payload && typeof detail.payload === 'object'
      ? JSON.stringify(detail.payload)
      : ''
    if (!payload) {
      throw new Error('NOTFOUND')
    }
    importGameFromJson(payload)
    await showAlert(t('side.importOk'))
  } catch (err) {
    await showAlert(`${t('side.importFailed')}${err?.message || err}`)
  }
}

async function onRemoveLocalSave(id) {
  if (!(await showConfirm(t('side.confirmDeleteSave')))) return
  await deleteSavedRecord(id, myIdentity.id)
  await refreshLeaderboards()
}

// 组件挂载时初始化游戏
onMounted(() => {
  initGame()
})
