<script setup>
import { computed } from 'vue'
import { BLACK } from '@/composables'
import { locale, t } from '@/i18n/index.js'

const props = defineProps({
  moveLog: {
    type: Array,
    default: () => []
  },
  gameOver: {
    type: Boolean,
    default: false
  },
  scores: {
    type: Object,
    required: true
  },
  resultTitle: {
    type: String,
    default: ''
  },
  replayCursor: {
    type: Number,
    default: 0
  },
  localSaves: {
    type: Array,
    default: () => []
  },
  blackDisplayName: {
    type: String,
    default: ''
  },
  whiteDisplayName: {
    type: String,
    default: ''
  }
})

const emit = defineEmits([
  'replay-step',
  'export-game',
  'import-game',
  'save-local',
  'load-local-save',
  'remove-local-save',
  'open-all-saves'
])

const canExport = computed(() => props.moveLog.length > 0)

function emitReplay(step) {
  emit('replay-step', step)
}

function actorLabel(player) {
  return player === BLACK
    ? props.blackDisplayName
    : props.whiteDisplayName
}

function actorStoneLabel(player) {
  return player === BLACK ? '黑子' : '白子'
}

/** @param {{ savedAt?: string, moveCount?: number }} s */
function formatSavedLine(s) {
  void locale.value
  const payload = s?.payload || {}
  const rm = payload.resultMeta && typeof payload.resultMeta === 'object'
    ? payload.resultMeta
    : {}
  const black = Number.isFinite(Number(rm.blackScore)) ? Number(rm.blackScore) : '-'
  const white = Number.isFinite(Number(rm.whiteScore)) ? Number(rm.whiteScore) : '-'
  const ex = Number.isFinite(Number(rm.excitementScore)) ? Number(rm.excitementScore) : '-'
  const mc = Number.isFinite(Number(s?.moveCount)) ? Number(s.moveCount) : '-'
  let timeText = '-'
  if (s?.savedAt) {
    const d = new Date(s.savedAt)
    if (!Number.isNaN(d.getTime())) {
      const pad = (n) => String(n).padStart(2, '0')
      timeText = `${d.getFullYear()}/${pad(d.getMonth() + 1)}/${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`
    }
  }
  return `${black}:${white} - ${ex} 彩 - ${mc} 手 - ${timeText}`
}

/**
 * @param {{
 *   payload?: {
 *     playerNameBlack?: string,
 *     playerNameWhite?: string,
 *     winner?: 'black' | 'white' | 'draw'
 *   }
 * }} s
 */
function formatSavedPlayers(s) {
  void locale.value
  const payload = s?.payload || {}
  const winner = payload.winner || payload.w || ''
  const names = payload.playerNames && typeof payload.playerNames === 'object'
    ? payload.playerNames
    : {}
  const compactNames = Array.isArray(payload.n) ? payload.n : []
  const blackBase =
    String(
      payload.playerNameBlack ||
      names.black ||
      compactNames[0] ||
      ''
    ).trim() || t('player.default1')
  const whiteBase =
    String(
      payload.playerNameWhite ||
      names.white ||
      compactNames[1] ||
      ''
    ).trim() || t('player.default2')
  const black = winner === 'black' ? `${blackBase} 👑` : blackBase
  const white = winner === 'white' ? `${whiteBase} 👑` : whiteBase
  return `${black} ${t('scoreboard.vs')} ${white}`
}
</script>

