<template>
  <div class="scoreboard">
    <div class="scoreboard-side scoreboard-side--left">
      <div class="name-slot">
        <input
          class="name-input"
          :class="{ 'name-input--active': isBlackActive }"
          type="text"
          maxlength="24"
          autocomplete="nickname"
          :value="blackName"
          :placeholder="phBlack"
          :aria-label="t('player.labelBlack')"
          @input="onBlack($event)"
        >
        <span
          v-if="showBlackCrown"
          class="winner-crown"
          aria-label="winner"
        >👑</span>
      </div>
    </div>

    <div class="scoreboard-mid">
      <div class="score-item">
        <div
          class="piece-icon black"
          aria-hidden="true"
        />
        <div class="score-item-text">
          <div class="score-num">
            {{ scores.black }}
          </div>
        </div>
      </div>
      <div class="score-divider">
        {{ t('scoreboard.vs') }}
      </div>
      <div class="score-item score-item--right">
        <div class="score-item-text score-item-text--right">
          <div class="score-num">
            {{ scores.white }}
          </div>
        </div>
        <div
          class="piece-icon white"
          aria-hidden="true"
        />
      </div>
    </div>

    <div class="scoreboard-side scoreboard-side--right">
      <div class="name-slot">
        <input
          class="name-input"
          :class="{ 'name-input--active': isWhiteActive }"
          type="text"
          maxlength="24"
          autocomplete="nickname"
          :value="effectiveWhiteName"
          :placeholder="phWhite"
          :aria-label="t('player.labelWhite')"
          :disabled="isWhiteLocked"
          @input="onWhite($event)"
        >
        <span
          v-if="showWhiteCrown"
          class="winner-crown"
          aria-label="winner"
        >👑</span>
      </div>
    </div>
  </div>
</template>

<script setup>
import { computed } from 'vue'
import { locale, t } from '@/i18n/index.js'

const props = defineProps({
  scores: {
    type: Object,
    required: true
  },
  blackName: {
    type: String,
    default: ''
  },
  whiteName: {
    type: String,
    default: ''
  },
  gameMode: {
    type: String,
    default: 'pvp'
  },
  currentPlayer: {
    type: Number,
    default: 1
  },
  gameOver: {
    type: Boolean,
    default: false
  },
  winner: {
    type: String,
    default: null
  }
})

const emit = defineEmits(['update:blackName', 'update:whiteName'])

const phBlack = computed(() => {
  void locale.value
  return t('player.default1')
})

const phWhite = computed(() => {
  void locale.value
  return props.gameMode === 'pvc' ? t('roles.ai') : t('player.default2')
})
const isWhiteLocked = computed(() => props.gameMode === 'pvc')
const effectiveWhiteName = computed(() =>
  isWhiteLocked.value ? t('roles.ai') : props.whiteName
)

const isBlackActive = computed(() => !props.gameOver && props.currentPlayer === 1)
const isWhiteActive = computed(() => !props.gameOver && props.currentPlayer === 2)
const showBlackCrown = computed(() => props.gameOver && props.winner === 'black')
const showWhiteCrown = computed(() => props.gameOver && props.winner === 'white')

function clip(s) {
  return String(s).slice(0, 24)
}

function onBlack(ev) {
  emit('update:blackName', clip(ev.target.value))
}

function onWhite(ev) {
  if (isWhiteLocked.value) return
  emit('update:whiteName', clip(ev.target.value))
}
</script>

