<template>
  <div class="board-container">
    <div class="coords-frame">
      <div class="coord-row coord-row--top">
        <span
          v-for="file in files"
          :key="`top-${file}`"
          class="coord-label"
        >{{ file }}</span>
      </div>
      <div class="coord-main">
        <div class="coord-col coord-col--left">
          <span
            v-for="rank in ranks"
            :key="`left-${rank}`"
            class="coord-label"
          >{{ rank }}</span>
        </div>
        <div class="board-wrap">
          <div class="board">
            <Cell
              v-for="(cellValue, index) in board"
              :key="index"
              :cell-value="cellValue"
              :index="index"
              :piece-meta="pieceMetas[index] ?? null"
              :is-valid-move="validMoveSet.has(index)"
              :last-move-index="lastMoveIndex"
              :is-clickable="canInteract"
              :show-hint="!gameOver && canInteract"
              :move-gain="moveGainMap[index] ?? 0"
              :show-move-gain="showMoveGain && !gameOver && canInteract"
              :is-max-move-gain="
                showMoveGain &&
                  !gameOver &&
                  canInteract &&
                  Number(moveGainMap[index]) === maxMoveGain
              "
              @click="handleCellClick"
            />
          </div>
        </div>
        <div class="coord-col coord-col--right">
          <span
            v-for="rank in ranks"
            :key="`right-${rank}`"
            class="coord-label"
          >{{ rank }}</span>
        </div>
      </div>
      <div class="coord-row coord-row--bottom">
        <span
          v-for="file in files"
          :key="`bottom-${file}`"
          class="coord-label"
        >{{ file }}</span>
      </div>
    </div>
  </div>
</template>

<script setup>
import { computed } from 'vue'
import Cell from '@/components/Cell/Cell.vue'

const props = defineProps({
  board: {
    type: Array,
    required: true
  },
  validMoveSet: {
    type: Set,
    required: true
  },
  lastMoveIndex: {
    type: Number,
    default: -1
  },
  canInteract: {
    type: Boolean,
    default: true
  },
  gameOver: {
    type: Boolean,
    default: false
  },
  pieceMetas: {
    type: Array,
    default: () => []
  },
  moveGainMap: {
    type: Object,
    default: () => ({})
  },
  showMoveGain: {
    type: Boolean,
    default: false
  }
})

const emit = defineEmits(['cell-click'])
const files = ['a', 'b', 'c', 'd', 'e', 'f', 'g', 'h']
const ranks = ['1', '2', '3', '4', '5', '6', '7', '8']

const maxMoveGain = computed(() => {
  const values = Object.values(props.moveGainMap || {})
    .map((v) => Number(v))
    .filter((v) => Number.isFinite(v))
  if (values.length === 0) return -Infinity
  return Math.max(...values)
})

function handleCellClick(index) {
  emit('cell-click', index)
}
</script>

